/*
 * Look up the 1588 lkup table. Return ts_table_index as -1 if not finding matched entry.
 */
int plp_aperta2_tscpmod_1588_table_index_get (uint32_t speed_index,
                                  int *ts_table_index,
                                  uint32_t *table_size)
{
    int i;

    *ts_table_index = -1;
    for (i = 0; i < TSCPMOD_1588_LKUP_SIZE; i++) {
        /* 
         *  Since speed_id is already has encoded FEC information,
         *  fec_type is not used and hardcoded to phymod_fec_None. 
         */
        if (plp_aperta2_tscpmod_1588_lkup_table[i].mapped_spd_table_index == speed_index) {
            *ts_table_index = plp_aperta2_tscpmod_1588_lkup_table[i].ts_table_index;
            *table_size = plp_aperta2_tscpmod_1588_lkup_table[i].table_size;
            break;
        }
    }

    return PHYMOD_E_NONE;
}

/*
 * RX 1588 table entry is 64 bits, stored as a 3-uint32_t array, only 2 (64bits) is used.
 * Each 16 bits contains time info for a psuedo logical lane:
 *  bit 15: Resered. Not used.
 *  bit 14-bit 0: time.
 * This function will translate a uint32_t based array into a 20-bits based array.
 */
int plp_aperta2_tscpmod_rx_tbl_entry_to_psll_entry_map(uint32_t *tbl_entry, uint32_t *psll_entry)
{
    psll_entry[0] = tbl_entry[0] & 0xffff;
    psll_entry[1] = ((tbl_entry[0] >> 16) & 0xffff);
    psll_entry[2] = tbl_entry[1] & 0xffff;
    psll_entry[3] = ((tbl_entry[1] >> 16) & 0xffff);

    return PHYMOD_E_NONE;
}

/*
 * RX 1588 table entry is 64 bits, stored as a 3-uint32_t array, only 2 (64bits) is used.
 * Each 16 bits contains time info for a psuedo logical lane:
 *  bit 15: Resered. Not used.
 *  bit 14-bit 0 time.
 * This function will translate 16-bits based array to 32-bits based array.
 */
int plp_aperta2_tscpmod_psll_entry_to_rx_tbl_entry_map(uint32_t *psll_entry, uint32_t *tbl_entry)
{
    tbl_entry[0] = ((psll_entry[1] << 16) & 0xffff0000) | (psll_entry[0] & 0xffff);
    tbl_entry[1] = ((psll_entry[3] << 16) & 0xffff0000) | (psll_entry[2] & 0xffff);
    tbl_entry[2] = 0x00000000; /* Not used. */

    return PHYMOD_E_NONE;
}

